from flask import Flask, request, jsonify
import pickle
import os
from werkzeug.utils import secure_filename

app = Flask(__name__)

# Model storage directory
model_dir = 'models'

if not os.path.exists(model_dir):
    os.makedirs(model_dir)

# Allowed model file extensions
allowed_extensions = {'pickle'}

def validate_model_file(file):
    if '.' in file:
        file_extension = file.rsplit('.', 1)[1].lower()
        if file_extension in allowed_extensions:
            return True
    return False

@app.route('/upload', methods=['POST'])
def upload_model():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    
    if validate_model_file(file.filename):
        filename = secure_filename(file.filename)
        file.save(os.path.join(model_dir, filename))
        
        try:
            with open(os.path.join(model_dir, filename), 'rb') as f:
                model = pickle.load(f)
                
            # Store the loaded model in a secure manner (e.g., encrypted storage)
            # For simplicity, we'll store it in plaintext here
            with open(os.path.join(model_dir, 'loaded_model.pkl'), 'wb') as f:
                pickle.dump(model, f)
            
            return jsonify({'message': 'Model uploaded successfully'}), 200
        
        except Exception as e:
            return jsonify({'error': str(e)}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400

if __name__ == '__main__':
    app.run(debug=True)